// Extrae y valida los campos del body
const body = $input.first().json.body || $input.first().json;
const message = (body.message || '').trim().slice(0, 800);
const lang    = ['es','ca','en','ar','zh'].includes(body.lang) ? body.lang : 'es';
const session = body.session_id || 'anon';

if (!message) {
  throw new Error('Mensaje vacío');
}

const langLabels = {
  es: 'español',
  ca: 'català',
  en: 'English',
  ar: 'العربية',
  zh: '中文'
};

return [{ json: { message, lang, session, langLabel: langLabels[lang] } }];

// Extrae el texto de la respuesta de Claude y lo devuelve al widget
const response = $input.first().json;

if (response.error) {
  return [{ json: { reply: 'Lo siento, ha ocurrido un error. Por favor inténtalo de nuevo o contáctanos directamente.' } }];
}

const reply = response.content?.[0]?.text || 'Sin respuesta del asistente.';
const inputTokens  = response.usage?.input_tokens  || 0;
const outputTokens = response.usage?.output_tokens || 0;

console.log(`Tokens — entrada: ${inputTokens}, salida: ${outputTokens}`);

return [{ json: { reply, usage: { inputTokens, outputTokens } } }];
